"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[2332],{9191:e=>{e.exports=JSON.parse('{"lang":"it","resources":{"landing":{"meta":{"title":"Linguist - Traduci pagine web in privato | Estensione di traduzione per Chrome e Firefox","description":"Estensione di traduzione per Chrome e Firefox attenta alla privacy. Traduci all\'istante pagine web, testo selezionato, sottotitoli e messaggi. Funziona offline e supporta l\'integrazione di servizi di traduzione e API."},"navigation":{"features":{"content":"Funzionalit\xe0"},"blog":{"content":"Blog"},"docs":{"content":"Documentazione"},"github":{"content":"GitHub"}},"install":{"chrome":"Installa per Chrome","firefox":"Installa per Firefox"},"sections":{"hero":{"title":"Traduci le pagine web in modo fluido","description":"Linguist \xe8 un traduttore per browser flessibile, basato sui servizi di traduzione pi\xf9 diffusi.\\n\\nTraduci intere pagine web, testo selezionato, sottotitoli su Netflix o in videochiamata e messaggi privati. Ascolta le traduzioni e salva quelle pi\xf9 importanti nel tuo dizionario personale per imparare nuovi vocaboli, anche offline.\\n\\nLinguist \xe8 un\'alternativa moderna e attenta alla privacy alle estensioni di Google Traduttore. Provalo gratis."},"opensource":{"title":"Open source","content":"Linguist \xe8 un\'estensione di traduzione gratuita e <0>open source</0>. Non raccoglie n\xe9 vende i dati degli utenti.\\n\\nPuoi fare una <1>donazione</1> per sostenere Linguist e aiutarci a mantenere l\'indipendenza e un\'alta qualit\xe0.\\n\\nCondividi Linguist sui social media per farlo scoprire ad altre persone."},"support":{"title":"Supporto","content":"Se hai domande, contattaci <0/>.\\nSe hai trovato un bug e hai un account GitHub, ti invitiamo ad <1>aprire una issue</1>."},"createdBy":{"content":"Creato da <0/>."}},"features":{"title":"Funzionalit\xe0","items":{"offlineTranslation":{"title":"Traduzione offline e privacy","content":"Traduci il testo direttamente sul tuo dispositivo con il traduttore offline integrato. Il testo rimane privato e non viene inviato su internet.\\n\\nAttiva questa funzionalit\xe0 nelle opzioni per mantenere private le traduzioni quando lavori con email, documenti o messaggi personali.\\n\\nIl traduttore offline ti permette anche di tradurre le pagine senza connessione a internet, un\'opzione particolarmente utile in viaggio."},"fullPageTranslation":{"title":"Traduci intere pagine web","content":"Traduzione rapida e di alta qualit\xe0 di intere pagine in pochi clic.\\n\\nUsa una scorciatoia da tastiera per tradurre all\'istante. Passa il cursore sul testo tradotto per vedere l\'originale. Traduci anche le pagine private protette da login o paywall.\\n\\nImposta regole di traduzione automatica in base alla lingua o al dominio della pagina.\\n\\nLinguist modifica le pagine in modo minimo: interviene solo sul testo, preservando il layout e l\'esperienza d\'uso.\\n\\nAttiva la traduzione in tempo reale per le riunioni multilingue su Zoom, Google Meet e Microsoft Teams."},"selectedTextTranslation":{"title":"Traduci il testo selezionato su qualsiasi sito","content":"Trovi parole che non conosci mentre leggi un articolo online?\\nTi basta selezionare il testo sulla pagina e cliccare sul pulsante di traduzione.\\n\\nAscolta sia il testo originale che quello tradotto, e salva le traduzioni nel tuo dizionario per ripassarle in seguito."},"textTranslation":{"title":"Traduzione rapida del testo","content":"Hai bisogno di tradurre qualcosa al volo? Clicca sull\'icona di Linguist e inserisci il testo.\\n\\nNon serve cambiare scheda o aprire siti di traduzione. Traduci direttamente nel browser usando il servizio che preferisci."},"knowledgeBase":{"title":"Crea il tuo archivio personale","content":"Ogni traduzione viene salvata nella cronologia e puoi aggiungere le voci pi\xf9 importanti al tuo dizionario personale. Cerca nel dizionario e nella cronologia in qualsiasi momento.\\n\\nNon perdi nulla, nemmeno durante lunghe sessioni di ricerca o di studio.\\n\\nIl dizionario funziona offline, rendendo Linguist ideale per chi studia le lingue o viaggia e ha bisogno di accedere sempre alle proprie liste di vocaboli."},"customTranslators":{"title":"Integra servizi di traduzione e API","content":"Linguist ti permette di scegliere quale servizio di traduzione utilizzare.\\n\\nSupporta i provider pi\xf9 diffusi come Google, Yandex e Microsoft, con oltre 100 lingue disponibili.\\n\\nSe un servizio di cui hai bisogno non \xe8 incluso, puoi aggiungerlo come <0>traduttore personalizzato</0>.\\n\\nI traduttori personalizzati ti consentono di integrare qualsiasi sistema di traduzione: dai moderni servizi LLM come ChatGPT, DeepL, DeepSeek e Gemini, ai traduttori locali in esecuzione sul tuo dispositivo, come Ollama o LibreTranslate."}}},"faq":{"title":"FAQ","items":{"whatIsLinguist":{"title":"Cos\'\xe8 Linguist?","content":"Linguist \xe8 un\'estensione di traduzione per Chrome e Firefox progettata con la privacy al primo posto.\\n\\nTi permette di tradurre intere pagine web, testo selezionato, sottotitoli e messaggi direttamente nel browser, senza dover passare a siti di traduzione esterni."},"whyLinguist":{"title":"Perch\xe9 usare Linguist?","content":"Esistono molte estensioni per tradurre le pagine web e alcuni browser includono persino traduttori integrati. Quindi, perch\xe9 usare Linguist?\\n\\nLa maggior parte dei traduttori integrati e delle estensioni offre una flessibilit\xe0 limitata. Molti si affidano a un unico provider, come Google Traduttore o Microsoft Bing, mentre Firefox offre il proprio traduttore offline. Nella maggior parte dei casi, non puoi scegliere il servizio pi\xf9 adatto alle tue esigenze.\\n\\nSe la qualit\xe0 della traduzione non \xe8 sufficiente per ci\xf2 che ti serve, o se inviare testi privati a servizi di terze parti non \xe8 un\'opzione accettabile, molti strumenti non offrono valide alternative.\\n\\nInoltre, molti strumenti si concentrano su una sola funzione: alcuni traducono intere pagine, altri solo il testo selezionato.\\n\\nAllo stesso tempo, alcune estensioni di traduzione sono create principalmente per monetizzare. Funzionalit\xe0 come la cronologia o i dizionari personali possono richiedere un abbonamento e, a volte, persino opzioni di base come il tema scuro sono considerate premium.\\n\\nLinguist adotta un approccio diverso. \xc8 progettato per essere uno strumento di traduzione pratico. Puoi scegliere il servizio di traduzione che preferisci, passare da un provider all\'altro o aggiungere i tuoi traduttori personalizzati.\\n\\nLinguist riunisce tutto in un unico posto: traduci intere pagine web, testo selezionato, sottotitoli e messaggi, tenendo traccia delle traduzioni importanti nella cronologia e nel dizionario personale."},"theLinguistLogo":{"title":"Perch\xe9 il logo di Linguist \xe8 la Torre di Babele?","content":"Il logo di Linguist si ispira alla <wiki>Torre di Babele</wiki>, una delle storie pi\xf9 antiche sul linguaggio e la comunicazione.\\n\\nSecondo il racconto, un tempo le persone parlavano la stessa lingua e cercarono di costruire una torre che arrivasse fino al cielo. La torre non fu mai completata e l\'umanit\xe0 si disperse, iniziando a parlare lingue diverse. Da allora, le differenze linguistiche hanno spesso reso difficile la comunicazione.\\n\\nLinguist \xe8 nato per aiutare a risolvere questo problema.\\n\\nLa Torre di Babele nel logo \xe8 un richiamo a quella storia: tante lingue, tante culture e il costante impegno umano per comprendersi a vicenda. Linguist aiuta a superare queste barriere rendendo la traduzione semplice, flessibile e accessibile direttamente nel browser.\\n\\nIl logo riflette anche lo spirito del progetto. Linguist non \xe8 solo un\'altra interfaccia per \\"Google Traduttore\\". \xc8 creato da persone che hanno a cuore le lingue, la privacy e la tecnologia aperta. La Torre di Babele rappresenta la curiosit\xe0, l\'apprendimento e l\'idea che le differenze linguistiche debbano unire le persone, non separarle."},"imageTranslation":{"title":"Perch\xe9 Linguist non traduce il testo nelle immagini?","content":"Linguist si concentra su funzionalit\xe0 di traduzione affidabili e di alta qualit\xe0.\\n\\nAbbiamo studiato diversi approcci per tradurre il testo all\'interno delle immagini. Al momento, la maggior parte delle soluzioni disponibili non offre risultati costanti, specialmente se eseguite direttamente nel browser, un aspetto fondamentale per tutelare la privacy degli utenti.\\n\\nPer questo motivo, Linguist attualmente non include la traduzione delle immagini. Preferiamo non rilasciare funzionalit\xe0 che non soddisfano i nostri standard di qualit\xe0.\\n\\nSe in futuro troveremo un modo affidabile e rispettoso della privacy per implementare la traduzione delle immagini, saremo felici di aggiungerla."},"howTranslatePages":{"title":"Come fa Linguist a tradurre le pagine web?","content":"Linguist pu\xf2 tradurre intere pagine web in pochi clic. Puoi avviare la traduzione della pagina usando il pulsante dell\'estensione o una scorciatoia da tastiera.\\n\\nIl testo originale rimane sempre accessibile. Passa il cursore sul testo tradotto per vedere l\'originale."},"offlineTranslation":{"title":"Linguist pu\xf2 tradurre le pagine offline?","content":"S\xec. Linguist include un traduttore offline integrato che ti permette di tradurre il testo senza inviare dati su internet.\\n\\nQuesto aiuta a proteggere la tua privacy e ti consente di tradurre i contenuti anche senza una connessione a internet."},"privacy":{"title":"Linguist rispetta la privacy?","content":"S\xec. Linguist \xe8 progettato con un\'attenzione particolare alla privacy.\\n\\nL\'estensione non raccoglie n\xe9 vende i dati degli utenti. Quando usi il <offline-translator>traduttore offline</offline-translator>, le traduzioni vengono elaborate interamente sul tuo dispositivo."},"supportedBrowsers":{"title":"Quali browser supporta Linguist?","content":"Linguist \xe8 disponibile per Chrome e Firefox. Funziona anche in altri browser basati su Chromium che supportano le estensioni di Chrome.\\n\\nLinguist \xe8 compatibile anche con i browser per Android che supportano le estensioni, come Firefox per Android e alcuni browser basati su Chromium."},"selectedText":{"title":"Linguist pu\xf2 tradurre il testo selezionato?","content":"S\xec. Ti basta selezionare il testo su qualsiasi pagina web e usare il pulsante di traduzione per tradurlo all\'istante.\\n\\nPuoi anche ascoltare la traduzione e salvarla nel tuo dizionario personale."},"customTranslators":{"title":"Posso usare il mio servizio di traduzione?","content":"S\xec. Linguist supporta i <custom-translator>traduttori personalizzati</custom-translator>, che ti permettono di integrare ulteriori servizi di traduzione.\\n\\nPuoi collegare API esterne o sistemi di traduzione locali come <libre-translate>LibreTranslate</libre-translate> o <ollama>Ollama</ollama>."},"isFree":{"title":"Linguist \xe8 gratuito?","content":"S\xec. Linguist \xe8 completamente gratuito e <linguist>open source</linguist>.\\n\\nIl progetto \xe8 sostenuto dalla community e, se lo desideri, puoi <donations>supportarlo con una donazione</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bg","langName":"\u0431\u044a\u043b\u0433\u0430\u0440\u0441\u043a\u0438","url":"https://linguister.io/bg"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"ca","langName":"catal\xe0","url":"https://linguister.io/ca"},{"langCode":"cs","langName":"\u010de\u0161tina","url":"https://linguister.io/cs"},{"langCode":"da","langName":"dansk","url":"https://linguister.io/da"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"el","langName":"\u0395\u03bb\u03bb\u03b7\u03bd\u03b9\u03ba\u03ac","url":"https://linguister.io/el"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fa","langName":"\u0641\u0627\u0631\u0633\u06cc","url":"https://linguister.io/fa"},{"langCode":"fi","langName":"suomi","url":"https://linguister.io/fi"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"he","langName":"\u05e2\u05d1\u05e8\u05d9\u05ea","url":"https://linguister.io/he"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"hu","langName":"magyar","url":"https://linguister.io/hu"},{"langCode":"id","langName":"Indonesia","url":"https://linguister.io/id"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ka","langName":"\u10e5\u10d0\u10e0\u10d7\u10e3\u10da\u10d8","url":"https://linguister.io/ka"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"nb","langName":"norsk bokm\xe5l","url":"https://linguister.io/nb"},{"langCode":"nl","langName":"Nederlands","url":"https://linguister.io/nl"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pl","langName":"polski","url":"https://linguister.io/pl"},{"langCode":"pt-BR","langName":"portugu\xeas (Brasil)","url":"https://linguister.io/pt-BR"},{"langCode":"pt-PT","langName":"portugu\xeas europeu","url":"https://linguister.io/pt-PT"},{"langCode":"ro","langName":"rom\xe2n\u0103","url":"https://linguister.io/ro"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"sl","langName":"sloven\u0161\u010dina","url":"https://linguister.io/sl"},{"langCode":"sr","langName":"\u0441\u0440\u043f\u0441\u043a\u0438","url":"https://linguister.io/sr"},{"langCode":"sv","langName":"svenska","url":"https://linguister.io/sv"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"te","langName":"\u0c24\u0c46\u0c32\u0c41\u0c17\u0c41","url":"https://linguister.io/te"},{"langCode":"th","langName":"\u0e44\u0e17\u0e22","url":"https://linguister.io/th"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"uk","langName":"\u0443\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0430","url":"https://linguister.io/uk"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh-CN","langName":"\u4e2d\u6587\uff08\u4e2d\u56fd\uff09","url":"https://linguister.io/zh-CN"},{"langCode":"zh-TW","langName":"\u4e2d\u6587\uff08\u53f0\u7063\uff09","url":"https://linguister.io/zh-TW"}]}')}}]);